import re
import logging
from flask import Flask, request, jsonify
from kafka import KafkaProducer
from kafka.errors import KafkaError

app = Flask(__name__)
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Configuration
KAFKA_BOOTSTRAP_SERVERS = ['localhost:9092']
KAFKA_SASL_MECHANISM = 'SCRAM-SHA-256'
KAFKA_SECURITY_PROTOCOL = 'SASL_SSL'

# Allowlist of topics that this API is permitted to publish to.
# This is the primary security control - never allow arbitrary topic names from user input.
ALLOWED_TOPICS = frozenset({
    'events.user.activity',
    'events.user.signup',
    'events.order.created',
    'events.order.updated',
    'events.notification.email',
    'events.notification.sms',
})

# Strict pattern for topic name validation (defense in depth)
TOPIC_NAME_PATTERN = re.compile(r'^[a-zA-Z0-9][a-zA-Z0-9._-]{0,248}$')

# Maximum message size in bytes
MAX_MESSAGE_SIZE = 1_048_576  # 1 MB


def create_producer():
    """Create a Kafka producer with secure configuration."""
    try:
        producer = KafkaProducer(
            bootstrap_servers=KAFKA_BOOTSTRAP_SERVERS,
            security_protocol=KAFKA_SECURITY_PROTOCOL,
            sasl_mechanism=KAFKA_SASL_MECHANISM,
            sasl_plain_username='event-publisher-service',
            sasl_plain_password='<configured-via-secrets-manager>',
            ssl_cafile='/etc/kafka/certs/ca-cert.pem',
            ssl_certfile='/etc/kafka/certs/client-cert.pem',
            ssl_keyfile='/etc/kafka/certs/client-key.pem',
            value_serializer=lambda v: v.encode('utf-8') if isinstance(v, str) else v,
            acks='all',
            retries=3,
            max_request_size=MAX_MESSAGE_SIZE,
            request_timeout_ms=30000,
        )
        return producer
    except KafkaError as e:
        logger.error("Failed to create Kafka producer: %s", e)
        raise


def validate_topic_name(topic_name: str) -> tuple[bool, str]:
    """
    Validate and authorize the requested topic name.

    Security controls:
    1. Input validation - reject malformed topic names
    2. Allowlist check - only permit publishing to pre-approved topics
    """
    if not topic_name:
        return False, "Topic name is required"

    if not isinstance(topic_name, str):
        return False, "Topic name must be a string"

    # Validate topic name format (defense in depth against injection)
    if not TOPIC_NAME_PATTERN.match(topic_name):
        return False, "Topic name contains invalid characters"

    # Block path traversal or special sequences
    if '..' in topic_name or topic_name.startswith('.') or topic_name.startswith('-'):
        return False, "Topic name contains disallowed sequences"

    # PRIMARY SECURITY CONTROL: Allowlist check
    # Never allow users to specify arbitrary topic names.
    # This prevents unauthorized access to internal/sensitive topics.
    if topic_name not in ALLOWED_TOPICS:
        logger.warning(
            "Rejected publish attempt to unauthorized topic: %s",
            topic_name
        )
        return False, f"Topic '{topic_name}' is not in the list of permitted topics"

    return True, ""


def validate_message(message: str) -> tuple[bool, str]:
    """Validate the message payload."""
    if not message:
        return False, "Message body is required"

    if not isinstance(message, str):
        return False, "Message must be a string"

    if len(message.encode('utf-8')) > MAX_MESSAGE_SIZE:
        return False, f"Message exceeds maximum size of {MAX_MESSAGE_SIZE} bytes"

    return True, ""


# Initialize producer at module level (reuse connections)
producer = None


def get_producer():
    global producer
    if producer is None:
        producer = create_producer()
    return producer


@app.route('/api/v1/publish', methods=['POST'])
def publish_message():
    """
    Publish a message to a Kafka topic.

    Expects JSON body:
    {
        "topic": "events.user.activity",
        "message": "your message content"
    }

    The topic MUST be in the configured allowlist.
    """
    try:
        data = request.get_json(force=False, silent=True)
        if not data:
            return jsonify({"error": "Invalid JSON body"}), 400

        topic_name = data.get('topic', '').strip()
        message = data.get('message', '')

        # Validate topic name against allowlist
        topic_valid, topic_error = validate_topic_name(topic_name)
        if not topic_valid:
            logger.info("Topic validation failed: %s (topic=%s)", topic_error, topic_name)
            return jsonify({"error": topic_error}), 400

        # Validate message
        msg_valid, msg_error = validate_message(message)
        if not msg_valid:
            return jsonify({"error": msg_error}), 400

        # Publish to the validated, allowlisted topic
        kafka_producer = get_producer()
        future = kafka_producer.send(topic_name, message)

        # Wait for confirmation
        record_metadata = future.get(timeout=10)

        logger.info(
            "Message published to topic=%s partition=%d offset=%d",
            record_metadata.topic,
            record_metadata.partition,
            record_metadata.offset,
        )

        return jsonify({
            "status": "published",
            "topic": record_metadata.topic,
            "partition": record_metadata.partition,
            "offset": record_metadata.offset,
        }), 200

    except KafkaError as e:
        logger.error("Kafka error during publish: %s", e)
        return jsonify({"error": "Failed to publish message"}), 503
    except Exception as e:
        logger.error("Unexpected error during publish: %s", e)
        return jsonify({"error": "Internal server error"}), 500


@app.route('/api/v1/topics', methods=['GET'])
def list_allowed_topics():
    """Return the list of topics available for publishing."""
    return jsonify({"allowed_topics": sorted(ALLOWED_TOPICS)}), 200


@app.route('/health', methods=['GET'])
def health_check():
    return jsonify({"status": "healthy"}), 200


